1	use pcode_model::{Instruction, Opcode, Operand, Program, SysCall, WORD};
2	use std::collections::{HashMap, HashSet};
3	use std::fmt::Write;
4	
5	/// Errors during assembly emission.
6	#[derive(Debug)]
7	pub enum EmitError {
8	    /// A fmt::Write call failed.
9	    Fmt(std::fmt::Error),
10	    /// Global variable offset too large for single-instruction access.
11	    GlobalOffsetTooLarge { addr: u32 },
12	    /// Local variable offset too large for single-instruction access.
13	    LocalOffsetTooLarge { offset: u8 },
14	    /// Argument access without known nargs for the containing procedure.
15	    UnknownNargs { pc: u32 },
16	}
17	
18	impl std::fmt::Display for EmitError {
19	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
20	        match self {
21	            EmitError::Fmt(e) => write!(f, "format error: {e}"),
22	            EmitError::GlobalOffsetTooLarge { addr } => {
23	                write!(f, "global offset too large: {addr} (max 42)")
24	            }
25	            EmitError::LocalOffsetTooLarge { offset } => {
26	                write!(f, "local offset too large: {offset} (max 41)")
27	            }
28	            EmitError::UnknownNargs { pc } => {
29	                write!(
30	                    f,
31	                    "loada/storea at PC=0x{pc:04X} but containing procedure has unknown nargs"
32	                )
33	            }
34	        }
35	    }
36	}
37	
38	impl std::error::Error for EmitError {}
39	
40	impl From<std::fmt::Error> for EmitError {
41	    fn from(e: std::fmt::Error) -> Self {
42	        EmitError::Fmt(e)
43	    }
44	}
45	
46	/// Initial stack pointer address. Programs start with sp set here;
47	/// the stack grows downward from this address.
48	const STACK_TOP: u32 = 0x2000;
49	
50	/// Frame header size in bytes: return address (3) + old fp (3).
51	const FRAME_HEADER: usize = 6;
52	
53	/// Emit COR24 assembly for a decoded p-code program.
54	///
55	/// Returns the complete assembly text as a string, ready to be written
56	/// to a `.s` file and assembled by the COR24 cross-assembler (as24).
57	pub fn emit_program(program: &Program, source_name: &str) -> Result<String, EmitError> {
58	    let mut e = Emitter::new(program);
59	    e.prologue(program, source_name)?;
60	    for instr in &program.instructions {
61	        e.instruction(instr)?;
62	    }
63	    e.epilogue(program)?;
64	    Ok(e.out)
65	}
66	
67	// ── Emitter ────────────────────────────────────────────────────────
68	
69	struct Emitter {
70	    out: String,
71	    /// P-code PCs that are jump/branch targets and need labels.
72	    targets: HashSet<u32>,
73	    /// Counter for generating unique skip labels (for conditional branches).
74	    skip_id: u32,
75	    /// Map from procedure entry PC to procedure info (nargs, num_locals).
76	    proc_info: HashMap<u32, ProcInfo>,
77	    /// Current procedure's info (set when we encounter an `enter`).
78	    current_proc: Option<ProcInfo>,
79	    /// Whether the _p24_divmod helper is needed.
80	    needs_divmod: bool,
81	}
82	
83	/// Minimal procedure info carried by the emitter.
84	#[derive(Debug, Clone, Copy)]
85	struct ProcInfo {
86	    nargs: u8,
87	    num_locals: u8,
88	}
89	
90	impl Emitter {
91	    fn new(program: &Program) -> Self {
92	        let mut proc_info = HashMap::new();
93	        for p in &program.procedures {
94	            proc_info.insert(
95	                p.entry_pc,
96	                ProcInfo {
97	                    nargs: p.nargs.unwrap_or(0),
98	                    num_locals: p.num_locals,
99	                },
100	            );
101	        }
102	        Self {
103	            out: String::with_capacity(8192),
104	            targets: collect_branch_targets(&program.instructions),
105	            skip_id: 0,
106	            proc_info,
107	            current_proc: None,
108	            needs_divmod: false,
109	        }
110	    }
111	
112	    fn next_skip(&mut self) -> u32 {
113	        let id = self.skip_id;
114	        self.skip_id += 1;
115	        id
116	    }
117	
118	    // ── Prologue / epilogue ────────────────────────────────────────
119	
120	    fn prologue(&mut self, program: &Program, source_name: &str) -> Result<(), EmitError> {
121	        writeln!(self.out, "; Generated by pc-aotc from {source_name}")?;
122	        writeln!(self.out, "; COR24 p-code AOT compiler output")?;
123	        writeln!(self.out)?;
124	        writeln!(self.out, "    la      sp, {STACK_TOP}")?;
125	        if program.entry_point != 0 {
126	            writeln!(self.out, "    la      r2, .L{:04X}", program.entry_point)?;
127	            writeln!(self.out, "    jmp     (r2)")?;
128	        }
129	        writeln!(self.out)?;
130	        Ok(())
131	    }
132	
133	    fn epilogue(&mut self, program: &Program) -> Result<(), EmitError> {
134	        // Halt loop (target for halt opcode)
135	        writeln!(self.out, "_p24_halt:")?;
136	        writeln!(self.out, "    bra     _p24_halt")?;
137	        writeln!(self.out)?;
