918	        writeln!(self.out, "    lw      r0, 6(sp)")?; // original dividend (pushed first, 2 above)
919	        writeln!(self.out, "    cls     r0, z")?;
920	        writeln!(self.out, "    brf     .Ldm_rpos")?;
921	        writeln!(self.out, "    lw      r1, 0(sp)")?; // |remainder|
922	        writeln!(self.out, "    mov     r0, z")?;
923	        writeln!(self.out, "    sub     r0, r1")?;
924	        writeln!(self.out, "    sw      r0, 0(sp)")?; // remainder = -|remainder|
925	        writeln!(self.out, ".Ldm_rpos:")?;
926	
927	        // Negate quotient if signs differ (dividend XOR divisor is negative)
928	        writeln!(self.out, "    lw      r0, 6(sp)")?; // original dividend
929	        writeln!(self.out, "    xor     r0, r2")?; // XOR with original divisor
930	        writeln!(self.out, "    cls     r0, z")?; // C = (XOR < 0) = signs differ
931	        writeln!(self.out, "    brf     .Ldm_qpos")?;
932	        writeln!(self.out, "    lw      r1, 3(sp)")?; // |quotient|
933	        writeln!(self.out, "    mov     r0, z")?;
934	        writeln!(self.out, "    sub     r0, r1")?;
935	        writeln!(self.out, "    sw      r0, 3(sp)")?; // quotient = -|quotient|
936	        writeln!(self.out, ".Ldm_qpos:")?;
937	
938	        // Load results: r0 = quotient, r1 = remainder
939	        writeln!(self.out, "    pop     r1")?; // remainder
940	        writeln!(self.out, "    pop     r0")?; // quotient
941	        writeln!(self.out, "    pop     r2")?; // discard original dividend
942	
943	        // Return: pop return address and jump
944	        writeln!(self.out, "    pop     r2")?; // return address
945	        writeln!(self.out, "    jmp     (r2)")?;
946	        writeln!(self.out)?;
947	
948	        Ok(())
949	    }
950	}
