954	/// Compute the frame offset for a local variable slot.
955	/// Local slot N is at fp - (N+1)*3.
956	fn local_frame_offset(slot: u8) -> Result<i8, EmitError> {
957	    let offset = -((slot as i16 + 1) * WORD as i16);
958	    if offset < -128 {
959	        return Err(EmitError::LocalOffsetTooLarge { offset: slot });
960	    }
961	    Ok(offset as i8)
962	}
963	
964	/// Compute the frame offset for an argument.
965	/// `arg[idx]` is at `fp + FRAME_HEADER + (nargs - 1 - idx) * 3`.
966	fn arg_frame_offset(nargs: u8, idx: u8) -> i16 {
967	    FRAME_HEADER as i16 + (nargs as i16 - 1 - idx as i16) * WORD as i16
968	}
