970	/// Sign-extend a 24-bit value stored in a u32 to an i32.
971	fn sign_extend_24(val: u32) -> i32 {
972	    if val & 0x80_0000 != 0 {
973	        (val | 0xFF00_0000) as i32
974	    } else {
975	        val as i32
976	    }
977	}
