979	/// Pre-scan instructions to find all PCs that are branch/jump targets.
980	fn collect_branch_targets(instructions: &[Instruction]) -> HashSet<u32> {
981	    let mut targets = HashSet::new();
982	    for instr in instructions {
983	        match instr.op {
984	            Opcode::Jmp | Opcode::Jz | Opcode::Jnz | Opcode::Call | Opcode::Calln => {
985	                match instr.operand {
986	                    Operand::Imm24(addr) => {
987	                        targets.insert(addr);
988	                    }
989	                    Operand::D8A24 { addr, .. } => {
990	                        targets.insert(addr);
991	                    }
992	                    _ => {}
993	                }
994	            }
995	            _ => {}
996	        }
997	    }
998	    // Also mark procedure entry points
999	    for instr in instructions {
1000	        if instr.op == Opcode::Enter {
1001	            targets.insert(instr.pc);
1002	        }
1003	    }
1004	    targets
1005	}
