//! Integration tests: build CFGs from real .p24 files and validate stack depth.

use pcode_analyze::{Cfg, propagate_stack_depth};
use pcode_model::decode_program;
use std::path::Path;

fn load_program(name: &str) -> pcode_model::Program {
    let path = Path::new(env!("CARGO_MANIFEST_DIR"))
        .join("../../tests/p24")
        .join(name);
    let bin = std::fs::read(&path).unwrap_or_else(|e| panic!("failed to read {}: {e}", path.display()));
    decode_program(&bin).unwrap()
}

/// Build CFGs for all procedures in a program and return block counts.
fn build_all_cfgs(prog: &pcode_model::Program) -> Vec<(u32, usize)> {
    let cfgs = Cfg::build_per_procedure(prog).unwrap();
    cfgs.iter().map(|(pc, cfg)| (*pc, cfg.blocks.len())).collect()
}

#[test]
fn arithmetic_cfg() {
    let prog = load_program("arithmetic.p24");
    let cfgs = build_all_cfgs(&prog);
    // Should have at least one procedure with blocks.
    assert!(!cfgs.is_empty());
    for (_, count) in &cfgs {
        assert!(*count > 0);
    }
}

#[test]
fn if_else_cfg_has_branches() {
    let prog = load_program("if_else.p24");
    let cfgs = Cfg::build_per_procedure(&prog).unwrap();
    // The main procedure should have multiple basic blocks due to if/else.
    let (_, main_cfg) = cfgs.last().unwrap(); // main is typically last
    assert!(
        main_cfg.blocks.len() >= 3,
        "if_else should have at least 3 basic blocks, got {}",
        main_cfg.blocks.len()
    );
}

#[test]
fn while_loop_cfg_has_back_edge() {
    let prog = load_program("while_loop.p24");
    let cfgs = Cfg::build_per_procedure(&prog).unwrap();
    let (_, main_cfg) = cfgs.last().unwrap();
    // A while loop creates a back-edge: some block should have a successor
    // that is earlier in address order (the loop header).
    let has_back_edge = main_cfg.blocks.values().any(|b| {
        b.successors.iter().any(|&s| s < b.start_pc)
    });
    assert!(has_back_edge, "while_loop should have at least one back-edge");
}

#[test]
fn recursion_cfg() {
    let prog = load_program("recursion.p24");
    let cfgs = build_all_cfgs(&prog);
    // Recursive program should have multiple procedures.
    assert!(cfgs.len() >= 2, "recursion should have at least 2 procedures");
}

#[test]
fn all_programs_stack_depth_consistent() {
    let names = [
        "arithmetic.p24",
        "if_else.p24",
        "while_loop.p24",
        "locals.p24",
        "globals.p24",
        "procedure_call.p24",
        "recursion.p24",
        "nested_calls.p24",
    ];
    for name in &names {
        let prog = load_program(name);
        let cfgs = Cfg::build_per_procedure(&prog).unwrap();
        for (entry_pc, cfg) in &cfgs {
            let result = propagate_stack_depth(cfg, &prog.instructions, 0);
            assert!(
                result.is_ok(),
                "{name}: stack depth error in procedure at 0x{entry_pc:04X}: {}",
                result.unwrap_err()
            );
        }
    }
}

#[test]
fn cfg_reverse_postorder_visits_all_reachable() {
    let prog = load_program("if_else.p24");
    let cfgs = Cfg::build_per_procedure(&prog).unwrap();
    for (_, cfg) in &cfgs {
        let rpo = cfg.reverse_postorder();
        // RPO should visit all reachable blocks.
        // (Some blocks might be unreachable dead code, so rpo.len() <= blocks.len())
        assert!(!rpo.is_empty() || cfg.blocks.is_empty());
    }
}

