252	    // Step 4: Compare
253	    if expected == actual {
254	        DiffTestResult {
255	            name: name.to_string(),
256	            status: DiffTestStatus::Pass,
257	        }
258	    } else {
259	        // Build a useful diff message
260	        let exp_lines: Vec<&str> = expected.lines().collect();
261	        let act_lines: Vec<&str> = actual.lines().collect();
262	        let mut diff_msg = String::new();
263	        diff_msg.push_str(&format!(
264	            "expected {} lines, got {} lines\n",
265	            exp_lines.len(),
266	            act_lines.len()
267	        ));
268	        let max = exp_lines.len().max(act_lines.len()).min(20);
269	        for i in 0..max {
270	            let exp = exp_lines.get(i).unwrap_or(&"<missing>");
271	            let act = act_lines.get(i).unwrap_or(&"<missing>");
272	            if exp != act {
273	                diff_msg.push_str(&format!(
274	                    "  line {}: expected {:?}, got {:?}\n",
275	                    i + 1,
276	                    exp,
277	                    act
278	                ));
279	            }
280	        }
281	        DiffTestResult {
282	            name: name.to_string(),
283	            status: DiffTestStatus::Fail(format!("output mismatch:\n{diff_msg}")),
284	        }
285	    }
286	}
